#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	register int res=0;register char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch>='0'&&ch<='9')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10,M=2e6+10,Mod=998244353;
struct Graph
{
	int head[N],des[M],nxt[M],cnt,deg[N];
	inline void ins(register int x,register int y){nxt[++cnt]=head[x];++deg[des[head[x]=cnt]=y];}
}b,c;
long long a[N],mul=1,val[N],tag[N],Mul[N],Cnt[N];int pos[N],n,que[N],H,T,m;
vector<int> data[N];
inline int qpow(int a,int b=Mod-2){int res=1;while(b){(b&1)?res=1ll*res*a%Mod:0;a=1ll*a*a%Mod;b=b>>1;}return res;}
inline void debug(){printf("mul %lld\n",mul);putchar('a');rep(11,16,i)printf(" %lld",mul*qpow(tag[i])%Mod*a[i]%Mod);puts("");}
inline void Init(){memset(a,0,sizeof(a));rep(1,n,i)tag[i]=1;mul=1;}
inline void func(int k)
{
	if(pos[k]==-1){if(!val[k])Init();else mul=mul*val[k]%Mod;return;}
	if(pos[k]){a[pos[k]]=(mul*qpow(tag[pos[k]])%Mod*a[pos[k]]%Mod+val[k])%Mod;tag[pos[k]]=mul;return;}
	int sz=data[k].size();rep(0,sz-1,i){func(data[k][i]);}return;
}
inline void topo()
{
	H=1;T=0;rep(0,m,i)c.deg[i]?0:que[++T]=i;
	while(H<=T)
	{
		register int u=que[H++];
		grep(c,u,i)
		{
			register int v=c.des[i];
			Mul[v]=Mul[v]*Mul[u]%Mod;
			(--c.deg[v])?0:que[++T]=v;
		}
	}
	H=1;T=0;rep(0,m,i)b.deg[i]?0:que[++T]=i;
	while(H<=T)
	{
		register int u=que[H++],cur=1;
		grep(b,u,i)
		{
			register int v=b.des[i];
			Cnt[v]=(Cnt[v]+Cnt[u]*cur%Mod)%Mod;
			cur=1ll*cur*Mul[v]%Mod;
			(--b.deg[v])?0:que[++T]=v;
		}
	}
}
int main()
{
	n=read();rep(1,n,i)a[i]=read(),tag[i]=1;
	m=read();rep(1,m,i)
	{
		register int q,opt=read(),v;
		Mul[i]=1;switch(opt)
		{
			case 1: pos[i]=read(),val[i]=read();break;
			case 2: pos[i]=-1,Mul[i]=read();break;
			case 3: q=read();while(q--){v=read();b.ins(i,v),c.ins(v,i);};break;
		}
	}
	int Q=read();Cnt[0]=Mul[0]=1;rep(1,Q,i){int v=read();b.ins(0,v);c.ins(v,0);}
//	rep(0,m,i)grep(c,i,j)printf("%d' %d'\n",i,c.des[j]);
	topo();rep(1,n,i)a[i]=a[i]*Mul[0]%Mod;
//	rep(0,n,i)printf("%lld ",Mul[i]);puts("");
	rep(1,m,i)if(pos[i]>0){a[pos[i]]=(a[pos[i]]+Cnt[i]*val[i]%Mod)%Mod;}
	rep(1,n,i)printf("%lld ",a[i]%Mod);return 0;
}
